namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public required string Code { get; set; }
    public required string Title { get; set; }
    public required string Description { get; set; }
    public int Credits { get; set; }
    public required string Schedule { get; set; }
    public required string InstructorName { get; set; }
    public required string InstructorBio { get; set; }
    public int DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public required string Name { get; set; }
    public required string Code { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string Name { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 uppercase alphanumeric characters.")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS" },
        new() { Id = 2, Name = "Mathematics", Code = "MATH" },
        new() { Id = 3, Name = "Physics", Code = "PHYS" },
        new() { Id = 4, Name = "English", Code = "ENG" },
        new() { Id = 5, Name = "History", Code = "HIST" },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design principles.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 2, Code = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and computational complexity. He previously worked at Google Research before joining academia.", DepartmentId = 1, IsFeatured = true },
        new() { Id = 3, Code = "CS301", Title = "Database Systems", Description = "Relational database design, SQL, transaction management, and introduction to NoSQL systems. Includes a semester-long project building a full database application.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez is a database systems expert with industry experience at Oracle and Amazon. Her research focuses on distributed database architectures.", DepartmentId = 1, IsFeatured = false },
        new() { Id = 4, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning mathematics educator who has taught calculus for over 20 years. He is known for making complex concepts accessible.", DepartmentId = 2, IsFeatured = true },
        new() { Id = 5, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Watts", InstructorBio = "Dr. Watts researches applications of linear algebra in machine learning. She collaborates with industry partners on applied mathematics problems.", DepartmentId = 2, IsFeatured = false },
        new() { Id = 6, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Lecture and laboratory components covering Newton's laws, energy conservation, and oscillatory motion.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Alan Torres", InstructorBio = "Dr. Torres is an experimental physicist whose research involves particle detection systems. He brings real-world lab experience into the classroom.", DepartmentId = 3, IsFeatured = false },
        new() { Id = 7, Code = "PHYS201", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Prerequisites: General Physics I and Calculus I.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Nina Patel", InstructorBio = "Dr. Patel is a theoretical physicist specializing in electromagnetic theory and photonics. She holds patents in optical sensor technology.", DepartmentId = 3, IsFeatured = true },
        new() { Id = 8, Code = "ENG101", Title = "Academic Writing", Description = "Develop skills in critical reading, argumentation, and clear academic prose. Students complete multiple essay assignments with peer review.", Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a published author and composition specialist. He has directed university writing programs for over a decade.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 9, Code = "ENG205", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present. Explores themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Prof. Rachel Green", InstructorBio = "Prof. Green specializes in 20th-century American fiction and has published two books on the Harlem Renaissance literary movement.", DepartmentId = 4, IsFeatured = false },
        new() { Id = 10, Code = "HIST101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Thomas Reid", InstructorBio = "Dr. Reid is a medieval historian with expertise in cross-cultural interactions along the Silk Road. He has led archaeological expeditions in Central Asia.", DepartmentId = 5, IsFeatured = false },
        new() { Id = 11, Code = "HIST202", Title = "Modern European History", Description = "Political, social, and cultural transformations in Europe from the French Revolution to the present day.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Clara Johansson", InstructorBio = "Dr. Johansson studies modern European political movements and nationalism. She previously held a fellowship at the European University Institute.", DepartmentId = 5, IsFeatured = true },
    ];

    public IReadOnlyList<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

